/**
 * Tests for prompt/goal-tracker (M140 G3 #1790)
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { existsSync, mkdtempSync, readFileSync, rmSync, writeFileSync, mkdirSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

import { goalTracker, extractGoalCondition } from '../../prompt/goal-tracker.js';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';

let tmp: string;

beforeEach(() => {
  tmp = mkdtempSync(join(tmpdir(), 'goal-tracker-'));
});

afterEach(() => {
  rmSync(tmp, { recursive: true, force: true });
});

describe('extractGoalCondition', () => {
  it('extracts condition from prompt starting with /goal', () => {
    expect(extractGoalCondition('/goal until tests pass')).toBe('until tests pass');
  });

  it('extracts condition from /goal on later line', () => {
    expect(
      extractGoalCondition('some preamble\n/goal until convergence'),
    ).toBe('until convergence');
  });

  it('returns null for non-/goal prompts', () => {
    expect(extractGoalCondition('regular prompt with no goal directive')).toBeNull();
    expect(extractGoalCondition('')).toBeNull();
  });
});

describe('goalTracker hook', () => {
  it('appends a started entry to goal-history.jsonl on /goal', () => {
    const ctx = createTestContext({ projectDir: tmp, sessionId: 'sess-A' });
    const input: HookInput = {
      tool_name: '',
      session_id: 'sess-A',
      tool_input: {},
      prompt: '/goal converge on green tests',
    };

    const result = goalTracker(input, ctx);

    expect(result).toEqual({ continue: true, suppressOutput: true });
    const path = join(tmp, '.claude', 'state', 'goal-history.jsonl');
    expect(existsSync(path)).toBe(true);
    const content = readFileSync(path, 'utf8').trim();
    const parsed = JSON.parse(content);
    expect(parsed.session_id).toBe('sess-A');
    expect(parsed.condition).toBe('converge on green tests');
    expect(parsed.started_at).toBeTruthy();
    expect(parsed.ended_at).toBeNull();
    expect(parsed.started_token_estimate).toBeGreaterThan(0);
  });

  it('returns silent success and writes nothing for non-/goal prompts', () => {
    const ctx = createTestContext({ projectDir: tmp, sessionId: 'sess-B' });
    const input: HookInput = {
      tool_name: '',
      session_id: 'sess-B',
      tool_input: {},
      prompt: 'just a regular prompt',
    };

    const result = goalTracker(input, ctx);
    expect(result).toEqual({ continue: true, suppressOutput: true });
    expect(existsSync(join(tmp, '.claude', 'state', 'goal-history.jsonl'))).toBe(false);
  });

  it('returns outputBlock when brake file exists', () => {
    const brakeDir = join(tmp, '.claude', 'state');
    mkdirSync(brakeDir, { recursive: true });
    writeFileSync(
      join(brakeDir, 'goal-budget-tripped.json'),
      JSON.stringify({
        tripped_at: '2026-05-12T12:00:00Z',
        session_id: 'prev',
        turns: 35,
        tokens: 100,
        reason: 'turns_cap',
      }),
    );

    const ctx = createTestContext({ projectDir: tmp, sessionId: 'sess-C' });
    const input: HookInput = {
      tool_name: '',
      session_id: 'sess-C',
      tool_input: {},
      prompt: '/goal try again',
    };

    const result = goalTracker(input, ctx);
    expect(result.continue).toBe(false);
    expect(result.stopReason).toMatch(/budget tripped/);
    expect(result.stopReason).toMatch(/turns_cap/);
    // Should NOT append history while brake is active
    const historyPath = join(tmp, '.claude', 'state', 'goal-history.jsonl');
    expect(existsSync(historyPath)).toBe(false);
  });
});
